// BusinessFeatureCreateBulk is the builder for creating many BusinessFeature entities in bulk.
type BusinessFeatureCreateBulk struct {
	config
	err      error
	builders []*BusinessFeatureCreate
	conflict []sql.ConflictOption
}

// Save creates the BusinessFeature entities in the database.
func (bfcb *BusinessFeatureCreateBulk) Save(ctx context.Context) ([]*BusinessFeature, error) {
	if bfcb.err != nil {
		return nil, bfcb.err
	}
	specs := make([]*sqlgraph.CreateSpec, len(bfcb.builders))
	nodes := make([]*BusinessFeature, len(bfcb.builders))
	mutators := make([]Mutator, len(bfcb.builders))
	for i := range bfcb.builders {
		func(i int, root context.Context) {
			builder := bfcb.builders[i]
			builder.defaults()
			var mut Mutator = MutateFunc(func(ctx context.Context, m Mutation) (Value, error) {
				mutation, ok := m.(*BusinessFeatureMutation)
				if !ok {
					return nil, fmt.Errorf("unexpected mutation type %T", m)
				}
				if err := builder.check(); err != nil {
					return nil, err
				}
				builder.mutation = mutation
				var err error
				nodes[i], specs[i] = builder.createSpec()
				if i < len(mutators)-1 {
					_, err = mutators[i+1].Mutate(root, bfcb.builders[i+1].mutation)
				} else {
					spec := &sqlgraph.BatchCreateSpec{Nodes: specs}
					spec.OnConflict = bfcb.conflict
					// Invoke the actual operation on the latest mutation in the chain.
					if err = sqlgraph.BatchCreate(ctx, bfcb.driver, spec); err != nil {
						if sqlgraph.IsConstraintError(err) {
							err = &ConstraintError{msg: err.Error(), wrap: err}
						}
					}
				}
				if err != nil {
					return nil, err
				}
				mutation.id = &nodes[i].ID
				mutation.done = true
				return nodes[i], nil
			})
			for i := len(builder.hooks) - 1; i >= 0; i-- {
				mut = builder.hooks[i](mut)
			}
			mutators[i] = mut
		}(i, ctx)
	}
	if len(mutators) > 0 {
		if _, err := mutators[0].Mutate(ctx, bfcb.builders[0].mutation); err != nil {
			return nil, err
		}
	}
	return nodes, nil
}

// SaveX is like Save, but panics if an error occurs.
func (bfcb *BusinessFeatureCreateBulk) SaveX(ctx context.Context) []*BusinessFeature {
	v, err := bfcb.Save(ctx)
	if err != nil {
		panic(err)
	}
	return v
}

